pub(crate) async fn recall_code_with_context(
    state: &Arc<AppState>,
    params: RecallCodeParams,
    context: Option<CodeToolContext>,
) -> anyhow::Result<CallToolResult> {
    use petgraph::graph::{DiGraph, NodeIndex};
    use std::collections::{HashMap, HashSet};

    let total_start = Instant::now();
    crate::ensure_embedding_ready!(state);
    let embedding_readiness_wait = total_start.elapsed();

    let RecallCodeParams {
        query,
        project_id,
        limit,
        mode: _,
        vector_weight,
        bm25_weight,
        ppr_weight,
        path_prefix,
        language,
        chunk_type,
    } = params;
    let mut timing = RecallCodeTimingEvidence::maybe_new(
        &query,
        project_id.as_deref(),
        limit,
        path_prefix.is_some(),
        language.is_some(),
        chunk_type.is_some(),
    );
    if let Some(timing) = timing.as_mut() {
        timing.record("embedding_readiness_wait", embedding_readiness_wait);
    }
    let project_resolution =
        resolve_project_for_code_tool(state, normalize_project_id(project_id), context.as_ref())
            .await;
    let project_id = project_resolution.project_id().map(str::to_string);

    let mut is_partial = false;
    let mut indexing_message = None;

    let stage_start = Instant::now();
    let mut project_status = None;
    if let Some(ref project_id) = project_id {
        if let Ok(Some(status)) = state.storage.get_index_status(project_id).await {
            if status.status == crate::types::IndexState::Indexing
                || status.status == crate::types::IndexState::EmbeddingPending
            {
                is_partial = true;
                indexing_message = Some(format!(
                    "Indexing in progress ({}/{} files). Results may be incomplete.",
                    status.indexed_files, status.total_files
                ));
            }
            project_status = Some(status);
        }
    }
    if let Some(timing) = timing.as_mut() {
        timing.record("index_status_read", stage_start.elapsed());
        timing.count("is_partial", is_partial);
        timing.count("status_seen", project_status.is_some());
    }

    let stage_start = Instant::now();
    let limit = normalize_limit(limit);

    if project_resolution.is_stale_binding() {
        let mut response = json!({
            "results": [],
            "count": 0,
            "summary": summary_collection_response(
                "collection",
                0,
                Some(0),
                true,
                Some("Session-bound project is stale; refusing cross-project fallback.".to_string()),
            ),
            "query": query,
            "contract": code_search_contract_json(project_id.as_deref(), project_status.as_ref()),
            "weights": {
                "vector": vector_weight.unwrap_or(DEFAULT_CODE_VECTOR_WEIGHT),
                "bm25": bm25_weight.unwrap_or(DEFAULT_CODE_BM25_WEIGHT),
                "ppr": ppr_weight.unwrap_or(DEFAULT_CODE_PPR_WEIGHT)
            },
            "is_partial": true,
            "message": "Session-bound project is stale; refusing cross-project fallback."
        });
        apply_project_resolution(&mut response, &project_resolution);
        if let Some(timing) = timing.as_mut() {
            timing.record("response_shaping", stage_start.elapsed());
            timing.count("results_count", 0usize);
            timing.count("has_degradation", false);
            timing.finish(true, 0);
        }
        return Ok(success_json(response));
    }

    let stage_start = Instant::now();
    let query_embedding = state.embedding.embed(&query).await?;
    if let Some(timing) = timing.as_mut() {
        timing.record("embedding_inference", stage_start.elapsed());
        timing.count("embedding_dim", query_embedding.len());
    }

    let stage_start = Instant::now();

    let vector_weight = vector_weight.unwrap_or(DEFAULT_CODE_VECTOR_WEIGHT);
    let bm25_weight = bm25_weight.unwrap_or(DEFAULT_CODE_BM25_WEIGHT);
    let ppr_weight = ppr_weight.unwrap_or(DEFAULT_CODE_PPR_WEIGHT);

    let project_id = project_id.as_deref();
    let query_lower = query.to_lowercase();
    let query_terms = split_identifier_tokens(&query);
    let codeish_query = is_codeish_query(&query, &query_terms);

    // ── Pre-filter configuration ───────────────────────────────────────────
    // Each channel is filtered independently BEFORE RRF merge so that
    // irrelevant results don't occupy rank slots and dilute precision.
    let path_prefix = path_prefix.as_deref();
    let language_filter = language.as_deref();
    let chunk_type_filter = chunk_type.as_deref();
    let has_filters =
        path_prefix.is_some() || language_filter.is_some() || chunk_type_filter.is_some();

    let matches_filters = |chunk: &crate::types::ScoredCodeChunk| -> bool {
        if let Some(prefix) = path_prefix {
            if !chunk.file_path.starts_with(prefix) {
                return false;
            }
        }
        if let Some(lang) = language_filter {
            // Language enum uses serde rename_all = "lowercase"
            let chunk_lang = serde_json::to_string(&chunk.language)
                .unwrap_or_default()
                .trim_matches('"')
                .to_string();
            if !chunk_lang.eq_ignore_ascii_case(lang) {
                return false;
            }
        }
        if let Some(ct) = chunk_type_filter {
            let chunk_ct = serde_json::to_string(&chunk.chunk_type)
                .unwrap_or_default()
                .trim_matches('"')
                .to_string();
            if !chunk_ct.eq_ignore_ascii_case(ct) {
                return false;
            }

pub fn rrf_merge(
    vector_results: &[(String, f32)],
    bm25_results: &[(String, f32)],
    ppr_results: &[(String, f32)],
    vector_weight: f32,
    bm25_weight: f32,
    ppr_weight: f32,
    limit: usize,
) -> Vec<(String, RrfScores)> {
    let mut scores: HashMap<String, RrfScores> = HashMap::new();

    for (rank, (id, original_score)) in vector_results.iter().enumerate() {
        let rrf_score = vector_weight / (RRF_K + rank as f32 + 1.0);
        let entry = scores.entry(id.clone()).or_default();
        entry.vector_score = *original_score;
        entry.combined_score += rrf_score;
    }

    for (rank, (id, original_score)) in bm25_results.iter().enumerate() {
        let rrf_score = bm25_weight / (RRF_K + rank as f32 + 1.0);
        let entry = scores.entry(id.clone()).or_default();
        entry.bm25_score = *original_score;
        entry.combined_score += rrf_score;
    }

    for (rank, (id, original_score)) in ppr_results.iter().enumerate() {
        let rrf_score = ppr_weight / (RRF_K + rank as f32 + 1.0);
        let entry = scores.entry(id.clone()).or_default();
        entry.ppr_score = *original_score;
        entry.combined_score += rrf_score;
    }

    let mut results: Vec<_> = scores.into_iter().collect();
    results.sort_by(|a, b| {
        b.1.combined_score
            .partial_cmp(&a.1.combined_score)
            .unwrap_or(std::cmp::Ordering::Equal)
    });
    results.truncate(limit);
    results
}

